#include <torch/extension.h>
#include <cuda_runtime.h>
#include <vector>
#include <cmath>

template<typename scalar_t>
__global__ void fused_conv_norm_kernel(
    const scalar_t* __restrict__ input,
    const scalar_t* __restrict__ weight,
    const scalar_t* __restrict__ bias,
    scalar_t* __restrict__ output,
    const float divide_by,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int input_h,
    const int input_w,
    const int kernel_size,
    const int output_h,
    const int output_w,
    const int padding,
    const int stride
) {
    // Use 2D grid for better parallelism
    const int h = blockIdx.x * blockDim.x + threadIdx.x;
    const int w = blockIdx.y * blockDim.y + threadIdx.y;
    const int c = blockIdx.z;

    if (h >= output_h || w >= output_w || c >= out_channels) return;

    // Precompute constants
    const int kernel_radius = kernel_size / 2;

    // Process all batches in this thread
    for (int n = 0; n < batch_size; n++) {
        scalar_t conv_result = 0.0;

        // Optimized convolution
        for (int kh = 0; kh < kernel_size; kh++) {
            const int ih = h * stride + kh - padding;
            if (ih < 0 || ih >= input_h) continue;

            for (int kw = 0; kw < kernel_size; kw++) {
                const int iw = w * stride + kw - padding;
                if (iw < 0 || iw >= input_w) continue;

                for (int ic = 0; ic < in_channels; ic++) {
                    const int input_idx = ((n * in_channels + ic) * input_h + ih) * input_w + iw;
                    const int weight_idx = ((c * in_channels + ic) * kernel_size + kh) * kernel_size + kw;
                    conv_result += input[input_idx] * weight[weight_idx];
                }
            }
        }

        // Add bias
        if (bias != nullptr) {
            conv_result += bias[c];
        }

        // Store convolution result
        const int output_idx = ((n * out_channels + c) / output_h + h) * output_w + w;
        output[output_idx] = conv_result;
    }
}

template<typename scalar_t>
__global__ void instance_norm_divide_kernel(
    scalar_t* __restrict__ data,
    const float divide_by,
    const int batch_size,
    const int channels,
    const int height,
    const int width
) {
    extern __shared__ float shared_mem[];

    const int spatial_size = height * width;
    const int c = blockIdx.x;
    const int n = blockIdx.y;
    const int tid = threadIdx.x;

    // Each thread processes multiple spatial positions
    const int elements_per_thread = (spatial_size + blockDim.x - 1) / blockDim.x;
    const int start_idx = tid * elements_per_thread;
    const int end_idx = min(start_idx + elements_per_thread, spatial_size);

    // Phase 1: Compute mean (parallel reduction)
    float thread_sum = 0.0f;
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
        thread_sum += (float)data[data_idx];
    }

    shared_mem[tid] = thread_sum;
    __syncthreads();

    // Parallel reduction in shared memory
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    const float mean = shared_mem[0] / spatial_size;

    // Phase 2: Compute variance
    float thread_var = 0.0f;
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
        const float diff = (float)data[data_idx] - mean;
        thread_var += diff * diff;
    }

    shared_mem[tid] = thread_var;
    __syncthreads();

    // Parallel reduction for variance
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    const float variance = shared_mem[0] / spatial_size;
    const float inv_std = rsqrtf(variance + 1e-5f);
    const float scale = inv_std / divide_by;

    // Phase 3: Apply normalization and division
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
