        output[output_idx] = conv_result;
    }
}

template<typename scalar_t>
__global__ void instance_norm_divide_kernel(
    scalar_t* __restrict__ data,
    const float divide_by,
    const int batch_size,
    const int channels,
    const int height,
    const int width
) {
    extern __shared__ float shared_mem[];

    const int spatial_size = height * width;
    const int c = blockIdx.x;
    const int n = blockIdx.y;
    const int tid = threadIdx.x;

    // Each thread processes multiple spatial positions
    const int elements_per_thread = (spatial_size + blockDim.x - 1) / blockDim.x;
    const int start_idx = tid * elements_per_thread;
    const int end_idx = min(start_idx + elements_per_thread, spatial_size);

    // Phase 1: Compute mean (parallel reduction)
    float thread_sum = 0.0f;
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
        thread_sum += (float)data[data_idx];
    }

    shared_mem[tid] = thread_sum;
    __syncthreads();

    // Parallel reduction in shared memory
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    const float mean = shared_mem[0] / spatial_size;

    // Phase 2: Compute variance
    float thread_var = 0.0f;
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
        const float diff = data[data_idx] - mean;
        thread_var += diff * diff;
    }

    shared_mem[tid] = thread_var;
    __syncthreads();

    // Parallel reduction for variance
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    const float variance = shared_mem[0] / spatial_size;
    const float inv_std = rsqrtf(variance + 1e-5f);
    const float scale = inv_std / divide_by;

    // Phase 3: Apply normalization and division
    for (int i = start_idx; i < end_idx; i++) {
        const int h = i / width;
        const int w = i % width;
        const int data_idx = ((n * channels + c) * height + h) * width + w;
        data[data_idx] = (scalar_t)(((float)data[data_idx] - mean) * scale);
    }
}

torch::Tensor fused_conv_norm_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float divide_by,
    int padding,
    int stride
) {
    auto batch_size = input.size(0);
    auto in_channels = input.size(1);
    auto input_h = input.size(2);
    auto input_w = input.size(3);
    auto out_channels = weight.size(0);
    auto kernel_size = weight.size(2);

    // Calculate output dimensions (same as PyTorch's Conv2d)
    auto output_h = (input_h + 2 * padding - kernel_size) / stride + 1;
    auto output_w = (input_w + 2 * padding - kernel_size) / stride + 1;

    auto output = torch::empty({batch_size, out_channels, output_h, output_w}, 
                              input.options());

    // Optimized convolution kernel launch configuration
    dim3 conv_block(8, 8, 1);
    dim3 conv_grid(
        (output_h + conv_block.x - 1) / conv_block.x,
        (output_w + conv_block.y - 1) / conv_block.y,
        out_channels
    );

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_conv_norm_cuda", ([&] {
        // First kernel: optimized convolution
        fused_conv_norm_kernel<scalar_t><<<conv_grid, conv_block>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            divide_by,
            batch_size,
            in_channels,
            out_channels,
            input_h,
            input_w,
            kernel_size,
            output_h,
            output_w,
            padding,
            stride
        );

        // Second kernel: optimized instance normalization with shared memory
        const int norm_threads = 256;
        const size_t shared_mem_size = norm_threads * sizeof(float);
        dim3 norm_grid(out_channels, batch_size);

        instance_norm_divide_kernel<scalar_t><<<norm_grid, norm_threads, shared_mem_size>>>(
            output.data_ptr<scalar_t>(),
            divide_by,
            batch_size,
            out_channels,
            output_h,
            output_w
        );
    }));

    cudaDeviceSynchronize();
    return output;
}
